const parts = input.split(/^-{3,}$/m);
if (parts.length < 2) {
  return { output: '', error: 'Format: rules (one per line: find -> replace), then ---, then the text to process.' };
}
const rulesRaw = parts[0].trim().split('\n').filter(l => l.includes('->'));
const text = parts.slice(1).join('---');
let result = text;
let appliedCount = 0;
const log = [];
for (const rule of rulesRaw) {
  const arrowIdx = rule.indexOf('->');
  const lhs = rule.slice(0, arrowIdx).trim();
  const rhs = rule.slice(arrowIdx + 2).trim();
  // Check for /regex/flags syntax
  const reMatch = lhs.match(/^\/(.+)\/([gimsuy]*)$/);
  if (reMatch) {
    try {
      const re = new RegExp(reMatch[1], reMatch[2] || 'g');
      const before = result;
      result = result.replace(re, rhs);
      const n = (before.match(re) || []).length;
      log.push(`[regex] /${reMatch[1]}/${reMatch[2]} → "${rhs}" (${n} match${n===1?'':'es'})`);
      appliedCount += n;
    } catch (e) {
      log.push(`[error] Invalid regex "${lhs}": ${e.message}`);
    }
  } else {
    let count = 0;
    result = result.split(lhs).join(rhs);
    count = (text.split(lhs).length - 1);
    log.push(`[literal] "${lhs}" → "${rhs}" (${count} match${count===1?'':'es'})`);
    appliedCount += count;
  }
}
const header = log.join('\n') + '\n\n--- Result ---\n';
return { output: header + result, outputLanguage: 'text' };
